const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = value instanceof Date ? value : parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return pad(date.getDate()) + '/' + pad(date.getMonth() + 1) + '/' + date.getFullYear() + ' ' + pad(date.getHours()) + ':' + pad(date.getMinutes());
};

const body = $json.body ?? $json;
const deadlineRaw = body.deadline ?? body.dueDate ?? body.endDate;
const description = body.taskDescription ?? body.adminNote ?? body.sourceInput ?? body.description ?? null;
const note = body.adminNote ?? body.sourceInput ?? body.taskDescription ?? null;

const deadlineDate = parseDate(deadlineRaw);
const completedDate = parseDate(body.completedAt);
const createdDate = parseDate(body.createdAt);
const itemType = String(body.itemType || (body.subtaskId ? 'SUBTASK' : 'TASK')).toUpperCase();
const subtaskId = body.subtaskId ?? null;
const taskName = body.taskName ?? body.subtaskTitle ?? 'Untitled task';
const subtasks = Array.isArray(body.subtasks) ? body.subtasks : [];

return [
  {
    json: {
      itemType,
      id: body.id ?? null,
      taskId: body.taskId,
      taskName,
      taskDescription: description,
      adminNote: body.adminNote ?? null,
      sourceInput: body.sourceInput ?? null,

      assigneeEmail: body.assigneeEmail ?? body.assignedTo ?? null,
      managerEmail: body.managerEmail,
      ownerName: body.ownerName,

      priority: body.priority,
      status: body.status,
      eventType: body.eventType ?? null,
      eventMessage: body.eventMessage ?? null,

      deadline: deadlineDate?.toISOString() ?? deadlineRaw ?? null,
      deadlineDisplay:
        formatDate(deadlineRaw) ??
        (typeof deadlineRaw === 'string' ? deadlineRaw : null) ??
        'Chưa có deadline',

      createdAt: createdDate?.toISOString() ?? body.createdAt ?? null,
      createdAtDisplay: formatDate(body.createdAt),

      completedAt: completedDate?.toISOString() ?? null,
      completedAtDisplay: formatDate(body.completedAt),

      reminderCount: body.reminderCount ?? 0,
      note,

      parentTaskCode: body.parentTaskCode ?? body.taskId ?? null,
      parentTaskName: body.parentTaskName ?? null,
      parentDeadline: body.parentDeadline ?? null,
      subtaskId,
      subtaskTitle: body.subtaskTitle ?? (itemType === 'SUBTASK' ? taskName : null),
      positionIndex: body.positionIndex ?? null,
      workItemLabel: itemType === 'SUBTASK' ? 'Subtask: ' + (body.subtaskTitle || taskName || '-') : 'Task: ' + (taskName || '-'),

      subtasks,

      receivedAt: new Date().toISOString()
    }
  }
];

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return pad(date.getDate()) + '/' + pad(date.getMonth() + 1) + '/' + date.getFullYear() + ' ' + pad(date.getHours()) + ':' + pad(date.getMinutes());
};

const task = $json;
const status = String(task.status || '').toUpperCase();
const itemType = String(task.itemType || (task.subtaskId ? 'SUBTASK' : 'TASK')).toUpperCase();
const lineBreak = String.fromCharCode(10);

if (itemType === 'SUBTASK' || task.subtaskId) {
  return [];
}

if (task.eventType && task.eventType !== 'TASK_CREATED') {
  return [];
}

if (status && !['PENDING', 'TODO'].includes(status)) {
  return [];
}

const subtasks = Array.isArray(task.subtasks) ? task.subtasks : [];
const assignmentMap = {};

if (task.assigneeEmail) {
  assignmentMap[task.assigneeEmail] = {
    email: task.assigneeEmail,
    isMainAssignee: true,
    subtasks: []
  };
}

for (const subtask of subtasks) {
  const email =
    subtask.assignedTo ??
    subtask.assigned_to ??
    subtask.assigneeEmail ??
    subtask.assignee_email;

  if (!email) continue;

  if (!assignmentMap[email]) {
    assignmentMap[email] = {
      email,
      isMainAssignee: false,
      subtasks: []
    };
  }

  const subDeadlineRaw = subtask.deadline ?? subtask.dueDate ?? subtask.endDate;

  assignmentMap[email].subtasks.push({
    id: subtask.id ?? null,
    title: subtask.title ?? subtask.name ?? 'Subtask chưa có tên',
    deadline: parseDate(subDeadlineRaw)?.toISOString() ?? subDeadlineRaw ?? null,
    deadlineDisplay:
      subtask.deadlineDisplay ??
      formatDate(subDeadlineRaw) ??
      subDeadlineRaw ??
      'Chưa có deadline',
    priority: subtask.priority ?? 'MEDIUM',
    status: subtask.status ?? 'TODO'
  });
}

const assignments = Object.values(assignmentMap);

return assignments.map((assignment) => {
  const subtaskLines = assignment.subtasks.length
    ? assignment.subtasks
        .map((s, index) => {
          return (index + 1) + '. ' + s.title
            + lineBreak + '   Deadline: ' + s.deadlineDisplay
            + lineBreak + '   Priority: ' + s.priority
            + lineBreak + '   Status: ' + s.status;
        })
        .join(lineBreak + lineBreak)
    : 'Bạn không có task con riêng trong task này.';

  return {
    json: {
      taskId: task.taskId,
      taskName: task.taskName,
      taskDescription: task.taskDescription,
      adminNote: task.adminNote,
      sourceInput: task.sourceInput,

      managerEmail: task.managerEmail,
      ownerName: task.ownerName,

      priority: task.priority,
      status: task.status,

      deadline: task.deadline,
      deadlineDisplay: task.deadlineDisplay,

      eventType: task.eventType,
      eventMessage: task.eventMessage,

      recipientEmail: assignment.email,
      isMainAssignee: assignment.isMainAssignee,
      assignedSubtasks: assignment.subtasks,
      subtaskCount: assignment.subtasks.length,
      subtaskLines,

      roleText: assignment.isMainAssignee
        ? 'Bạn là người phụ trách chính của task cha.'
        : 'Bạn là thành viên được giao task con.',

      receivedAt: task.receivedAt
    }
  };
});

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const deadline = parseDate($json.deadline);
const completedAt = parseDate($json.completedAt) ?? new Date();
const isEarly = deadline ? completedAt.getTime() <= deadline.getTime() : false;

return [{
  json: {
    ...$json,
    deadline: deadline?.toISOString() ?? $json.deadline ?? null,
    deadlineDisplay: $json.deadlineDisplay ?? formatDate($json.deadline) ?? 'Chua co deadline',
    completedAt: completedAt.toISOString(),
    completedAtDisplay: formatDate(completedAt),
    isEarly
  }
}];
